# Define a dictionary to store authorization codes
auth_codes = {}

@app.route('/authorize', methods=['GET'])
def authorize():
    # Generate a random authorization code
    auth_code = ''.join(random.choice('abcdefghijklmnopqrstuvwxyz0123456789') for i in range(32))
    
    # Store the authorization code and user ID in the dictionary
    auth_codes[auth_code] = request.args.get('user_id')
    
    return jsonify({'authorization_code': auth_code})

@app.route('/token', methods=['POST'])
def token():
    # Retrieve the authorization code from the request body
    auth_code = request.form.get('code')
    
    # Check if the authorization code is valid
    if auth_code in auth_codes:
        # If the code is valid, return a token
        user_id = auth_codes[auth_code]
        del auth_codes[auth_code]
        
        return jsonify({'token': ''.join(random.choice('abcdefghijklmnopqrstuvwxyz0123456789') for i in range(32))})
    else:
        # If the code is not valid, return an error message
        return jsonify({'error': 'invalid_grant'}), 400